SELECT 
FROM t_owner_dispute
WHERE tenant_id = #{tenantId}
  AND raised_by_owner_id = #{ownerId}
ORDER BY raised_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT 
FROM t_owner_dispute
WHERE tenant_id = #{tenantId}

    AND current_review_level = #{level}


    AND status = #{status}

ORDER BY raised_at DESC
LIMIT #{limit} OFFSET #{offset}
